views["home.ejs"] = "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <title><%= title %> - <%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %></title>\n    <meta name=\"description\" content=\"Official website of <%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %>, a social and charity organization focusing on education, healthcare, rural development, women empowerment, youth, culture, and environment.\" />\n    <link\n      href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\"\n      rel=\"stylesheet\"\n    />\n    <link\n      rel=\"stylesheet\"\n      href=\"https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.3/font/bootstrap-icons.css\"\n    />\n    <link rel=\"stylesheet\" href=\"/static/css/style.css\" />\n  </head>\n  <body>\n    <header class=\"border-bottom bg-light\">\n      <div class=\"container py-2 py-md-2 d-flex flex-wrap justify-content-between align-items-center gap-2\">\n        <div class=\"d-flex align-items-center gap-2 gap-md-3 flex-shrink-0 min-w-0\">\n          <img src=\"<%= (settings && settings.header_logo_url) || '/static/images/logo.png' %>\" alt=\"Logo\" class=\"logo-img flex-shrink-0\" />\n          <div class=\"min-w-0\">\n            <span class=\"fw-bold text-primary d-block text-truncate\" style=\"font-size: clamp(0.9rem, 3vw, 1rem);\"><%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %></span>\n            <small class=\"text-muted d-none d-sm-inline\"><%= (settings && settings.site_tagline) || 'Seva | Shiksha | Sahyog' %></small>\n          </div>\n        </div>\n        <div class=\"d-none d-md-flex gap-2 flex-shrink-0\">\n          <a href=\"/get-involved\" class=\"btn btn-outline-primary btn-sm\">Join Us</a>\n          <a href=\"/get-involved#donate\" class=\"btn btn-primary btn-sm\">Donate</a>\n        </div>\n      </div>\n      <div class=\"container d-md-none mt-2 pb-2\">\n        <div class=\"d-flex justify-content-center gap-2\">\n          <a href=\"/get-involved\" class=\"btn btn-outline-primary btn-sm flex-grow-1 flex-md-grow-0\" style=\"min-width: 0;\">Join</a>\n          <a href=\"/get-involved#donate\" class=\"btn btn-primary btn-sm flex-grow-1 flex-md-grow-0\" style=\"min-width: 0;\">Donate</a>\n        </div>\n      </div>\n      <nav class=\"navbar navbar-expand-lg navbar-dark bg-primary\">\n        <div class=\"container\">\n          <a class=\"navbar-brand\" href=\"/\">Home</a>\n          <button\n            class=\"navbar-toggler\"\n            type=\"button\"\n            data-bs-toggle=\"collapse\"\n            data-bs-target=\"#mainNav\"\n            aria-controls=\"mainNav\"\n            aria-expanded=\"false\"\n            aria-label=\"Toggle navigation\"\n          >\n            <span class=\"navbar-toggler-icon\"></span>\n          </button>\n          <div class=\"collapse navbar-collapse\" id=\"mainNav\">\n            <ul class=\"navbar-nav me-auto mb-2 mb-lg-0\">\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/about\">About Us</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/activities\">Activities &amp; Programs</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/media\">Media &amp; Publications</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/get-involved\">Get Involved</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/contact\">Contact</a></li>\n            </ul>\n            <div class=\"d-flex gap-3 py-2 py-lg-0 justify-content-center justify-content-lg-end flex-wrap\">\n              <% let socialLinks = []; try { socialLinks = settings && settings.social_links_json ? JSON.parse(settings.social_links_json) : []; } catch (e) { socialLinks = []; } %>\n              <% if (!socialLinks.length) { %>\n                <a href=\"https://www.facebook.com/people/Aaryawart-Seva-Nyaas/61585981201970/\" class=\"text-white text-decoration-none\" aria-label=\"Facebook\"><i class=\"bi bi-facebook\"></i></a>\n                <a href=\"https://x.com/aaryawartastro\" class=\"text-white text-decoration-none\" aria-label=\"Twitter\"><i class=\"bi bi-twitter-x\"></i></a>\n                <a href=\"https://www.instagram.com/aaryawart_seva_nyaas/\" class=\"text-white text-decoration-none\" aria-label=\"Instagram\"><i class=\"bi bi-instagram\"></i></a>\n                <a href=\"https://www.youtube.com/@aaryawartastroworld\" class=\"text-white text-decoration-none\" aria-label=\"YouTube\"><i class=\"bi bi-youtube\"></i></a>\n                <a href=\"https://linkedin.com\" class=\"text-white text-decoration-none\" aria-label=\"LinkedIn\"><i class=\"bi bi-linkedin\"></i></a>\n              <% } else { %>\n                <% socialLinks.forEach(function(link) { %>\n                  <a href=\"<%= link.url %>\" class=\"text-white text-decoration-none\" aria-label=\"<%= link.id %>\"><i class=\"bi <%= link.icon %>\"></i></a>\n                <% }); %>\n              <% } %>\n            </div>\n          </div>\n        </div>\n      </nav>\n      <div class=\"news-ticker bg-warning text-dark\">\n        <div class=\"container\">\n          <span class=\"fw-bold me-2\">Latest:</span>\n          <marquee behavior=\"scroll\" direction=\"left\">\n            <%= (settings && settings.news_ticker_text) || 'Upcoming health camp in rural districts \u2022 National youth leadership workshop \u2022 Flood relief volunteer deployment \u2022 New education centers inaugurated' %>\n          </marquee>\n        </div>\n      </div>\n    </header>\n\n    <main>\n\n<% var heroExtra = {}; try { heroExtra = hero && hero.extra_json ? JSON.parse(hero.extra_json) : {}; } catch (e) { heroExtra = {}; } %>\n<section class=\"hero-section text-white d-flex align-items-center\" style=\"background-image: url('<%= heroExtra.backgroundImage || '/static/images/hero.jpg' %>');\">\n  <div class=\"container py-5\">\n    <div class=\"row align-items-center\">\n      <div class=\"col-md-7\">\n        <h1 class=\"display-5 fw-bold mb-3\"><%= (hero && hero.title) || 'Serving Society, Preserving Culture, Empowering Communities' %></h1>\n        <p class=\"lead mb-4\"><%= (hero && hero.body) || 'A nationwide volunteer movement working in education, healthcare, rural development, women empowerment, disaster relief, and cultural preservation.' %></p>\n        <div class=\"d-flex flex-wrap gap-2\">\n          <% var heroButtons = []; try { heroButtons = hero && hero.extra_json ? (JSON.parse(hero.extra_json).buttons || []) : []; } catch (e) { heroButtons = []; } %>\n          <% if (!heroButtons.length) { %>\n            <a href=\"/get-involved\" class=\"btn btn-light btn-lg\">Join Us</a>\n            <a href=\"/get-involved#donate\" class=\"btn btn-outline-light btn-lg\">Donate</a>\n            <a href=\"/about\" class=\"btn btn-outline-light btn-lg\">Learn More</a>\n          <% } else { %>\n            <% heroButtons.forEach(function(btn) { %>\n              <a href=\"<%= btn.url %>\" class=\"btn btn-<%= btn.variant || 'light' %> btn-lg\"><%= btn.label %></a>\n            <% }); %>\n          <% } %>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<section class=\"py-5\">\n  <div class=\"container\">\n    <div class=\"row text-center\">\n      <div class=\"col-md-4 mb-3\">\n        <h3><%= (mission && mission.title) || 'Our Mission' %></h3>\n        <p><%= (mission && mission.body) || 'To build a harmonious, self-reliant, and compassionate society through organized, selfless service rooted in timeless values.' %></p>\n      </div>\n      <div class=\"col-md-4 mb-3\">\n        <h3><%= (vision && vision.title) || 'Our Vision' %></h3>\n        <p><%= (vision && vision.body) || 'A nation where every individual is empowered, every village is vibrant, and cultural heritage guides modern progress.' %></p>\n      </div>\n      <div class=\"col-md-4 mb-3\">\n        <h3><%= (approach && approach.title) || 'Our Approach' %></h3>\n        <p><%= (approach && approach.body) || 'Grassroots initiatives led by trained volunteers, in partnership with communities, institutions, and well-wishers worldwide.' %></p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<section class=\"py-5 bg-light\">\n  <div class=\"container\">\n    <h2 class=\"text-center mb-4\">Our Impact</h2>\n    <div class=\"row text-center\">\n      <div class=\"col-md-4 mb-3\">\n        <div class=\"impact-card\">\n          <div class=\"impact-number\"><%= (stats && stats.volunteers_registered) || 2719 %></div>\n          <div class=\"impact-label\">Active Volunteers</div>\n        </div>\n      </div>\n      <div class=\"col-md-4 mb-3\">\n        <div class=\"impact-card\">\n          <div class=\"impact-number\"><%= (stats && stats.projects_completed) || 3 %></div>\n          <div class=\"impact-label\">Projects Completed</div>\n        </div>\n      </div>\n      <div class=\"col-md-4 mb-3\">\n        <div class=\"impact-card\">\n          <div class=\"impact-number\"><%= (stats && stats.lives_impacted) || 50000 %></div>\n          <div class=\"impact-label\">Lives Impacted</div>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<section class=\"py-5\">\n  <div class=\"container\">\n    <div class=\"row\">\n      <div class=\"col-md-8\">\n        <h2 class=\"mb-3\">Latest Activities</h2>\n        <% if (!latestBlogs || latestBlogs.length === 0) { %>\n          <p>No recent activities yet.</p>\n        <% } else { %>\n          <div class=\"list-group\">\n            <% latestBlogs.forEach(function(b) { %>\n              <a href=\"/media#blog-<%= b.id %>\" class=\"list-group-item list-group-item-action\">\n                <div class=\"d-flex w-100 justify-content-between\">\n                  <h5 class=\"mb-1\"><%= b.title %></h5>\n                  <small><%= b.publish_date %></small>\n                </div>\n                <p class=\"mb-1\"><%= (b.content || '').replace(/<[^>]+>/g, '').substring(0, 150) %>...</p>\n                <small><%= b.category || '' %> - <%= b.author %></small>\n              </a>\n            <% }); %>\n          </div>\n        <% } %>\n      </div>\n      <div class=\"col-md-4\">\n        <h2 class=\"mb-3\">Testimonials</h2>\n        <% if (testimonials && testimonials.length) { %>\n          <% testimonials.forEach(function(t) { %>\n            <% var tExtra = {}; try { tExtra = t.extra_json ? JSON.parse(t.extra_json) : {}; } catch (e) { tExtra = {}; } %>\n            <div class=\"testimonial mb-3\">\n              <p><%= t.body || '' %></p>\n              <% if (t.title || tExtra.attribution) { %>\n                <small class=\"text-muted\">-- <%= tExtra.attribution || t.title %></small>\n              <% } %>\n            </div>\n          <% }); %>\n        <% } else { %>\n          <div class=\"testimonial mb-3\">\n            <p>\"Volunteering here has given my life a new purpose.\"</p>\n            <small class=\"text-muted\">-- Ananya, Youth Volunteer</small>\n          </div>\n          <div class=\"testimonial mb-3\">\n            <p>\"Their programs have transformed our village schools.\"</p>\n            <small class=\"text-muted\">-- Village Sarpanch, Maharashtra</small>\n          </div>\n          <div class=\"testimonial\">\n            <p>\"Their teams are among the first to reach in times of disaster.\"</p>\n            <small class=\"text-muted\">-- District Collector, Assam</small>\n          </div>\n        <% } %>\n      </div>\n    </div>\n  </div>\n</section>\n<script src=\"/static/js/counters.js\"></script>\n\n    </main>\n\n    <footer class=\"bg-dark text-white mt-5 pt-4 pb-3\">\n      <div class=\"container\">\n        <div class=\"row\">\n          <div class=\"col-md-4 mb-3\">\n            <h5>About</h5>\n            <p class=\"small\">\n              <%= (settings && settings.footer_about) || 'A nationwide social and cultural organization dedicated to selfless service, character building, and national integration through thousands of volunteers and grassroots projects.' %>\n            </p>\n          </div>\n          <div class=\"col-md-4 mb-3\">\n            <h5>Quick Links</h5>\n            <ul class=\"list-unstyled small\">\n              <% let quickLinks = []; try { quickLinks = settings && settings.footer_quick_links_json ? JSON.parse(settings.footer_quick_links_json) : []; } catch (e) { quickLinks = []; } %>\n              <% if (!quickLinks.length) { %>\n                <li><a href=\"/about\" class=\"text-white text-decoration-none\">About Us</a></li>\n                <li><a href=\"/activities\" class=\"text-white text-decoration-none\">Activities</a></li>\n                <li><a href=\"/media\" class=\"text-white text-decoration-none\">Media</a></li>\n                <li><a href=\"/get-involved\" class=\"text-white text-decoration-none\">Volunteer / Donate</a></li>\n                <li><a href=\"/contact\" class=\"text-white text-decoration-none\">Contact</a></li>\n              <% } else { %>\n                <% quickLinks.forEach(function(link) { %>\n                  <li><a href=\"<%= link.url %>\" class=\"text-white text-decoration-none\"><%= link.label %></a></li>\n                <% }); %>\n              <% } %>\n            </ul>\n          </div>\n          <div class=\"col-md-4 mb-3\">\n            <h5>Contact</h5>\n            <% const footerContact = (settings && settings.footer_contact) || '113, Shivalik Nagar, BHEL, Haridwar, UK, India (249403)\\nEmail: aaryawartsevanyaas@gmail.com\\nPhone: +91-9253999082, 9253999083'; %>\n            <% footerContact.split(/\\r?\\n/).forEach(function(line) { %>\n              <p class=\"small mb-1\"><%= line %></p>\n            <% }); %>\n          </div>\n        </div>\n        <div class=\"text-center small mt-3\">\n          &copy; <%= new Date().getFullYear() %> <%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %>. All rights reserved.\n        </div>\n      </div>\n    </footer>\n\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js\"></script>\n    <script src=\"/static/js/main.js\"></script>\n  </body>\n</html>\n";
views["about.ejs"] = "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <title><%= title %> - <%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %></title>\n    <meta name=\"description\" content=\"Official website of <%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %>, a social and charity organization focusing on education, healthcare, rural development, women empowerment, youth, culture, and environment.\" />\n    <link\n      href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\"\n      rel=\"stylesheet\"\n    />\n    <link\n      rel=\"stylesheet\"\n      href=\"https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.3/font/bootstrap-icons.css\"\n    />\n    <link rel=\"stylesheet\" href=\"/static/css/style.css\" />\n  </head>\n  <body>\n    <header class=\"border-bottom bg-light\">\n      <div class=\"container py-2 py-md-2 d-flex flex-wrap justify-content-between align-items-center gap-2\">\n        <div class=\"d-flex align-items-center gap-2 gap-md-3 flex-shrink-0 min-w-0\">\n          <img src=\"<%= (settings && settings.header_logo_url) || '/static/images/logo.png' %>\" alt=\"Logo\" class=\"logo-img flex-shrink-0\" />\n          <div class=\"min-w-0\">\n            <span class=\"fw-bold text-primary d-block text-truncate\" style=\"font-size: clamp(0.9rem, 3vw, 1rem);\"><%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %></span>\n            <small class=\"text-muted d-none d-sm-inline\"><%= (settings && settings.site_tagline) || 'Seva | Shiksha | Sahyog' %></small>\n          </div>\n        </div>\n        <div class=\"d-none d-md-flex gap-2 flex-shrink-0\">\n          <a href=\"/get-involved\" class=\"btn btn-outline-primary btn-sm\">Join Us</a>\n          <a href=\"/get-involved#donate\" class=\"btn btn-primary btn-sm\">Donate</a>\n        </div>\n      </div>\n      <div class=\"container d-md-none mt-2 pb-2\">\n        <div class=\"d-flex justify-content-center gap-2\">\n          <a href=\"/get-involved\" class=\"btn btn-outline-primary btn-sm flex-grow-1 flex-md-grow-0\" style=\"min-width: 0;\">Join</a>\n          <a href=\"/get-involved#donate\" class=\"btn btn-primary btn-sm flex-grow-1 flex-md-grow-0\" style=\"min-width: 0;\">Donate</a>\n        </div>\n      </div>\n      <nav class=\"navbar navbar-expand-lg navbar-dark bg-primary\">\n        <div class=\"container\">\n          <a class=\"navbar-brand\" href=\"/\">Home</a>\n          <button\n            class=\"navbar-toggler\"\n            type=\"button\"\n            data-bs-toggle=\"collapse\"\n            data-bs-target=\"#mainNav\"\n            aria-controls=\"mainNav\"\n            aria-expanded=\"false\"\n            aria-label=\"Toggle navigation\"\n          >\n            <span class=\"navbar-toggler-icon\"></span>\n          </button>\n          <div class=\"collapse navbar-collapse\" id=\"mainNav\">\n            <ul class=\"navbar-nav me-auto mb-2 mb-lg-0\">\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/about\">About Us</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/activities\">Activities &amp; Programs</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/media\">Media &amp; Publications</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/get-involved\">Get Involved</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/contact\">Contact</a></li>\n            </ul>\n            <div class=\"d-flex gap-3 py-2 py-lg-0 justify-content-center justify-content-lg-end flex-wrap\">\n              <% let socialLinks = []; try { socialLinks = settings && settings.social_links_json ? JSON.parse(settings.social_links_json) : []; } catch (e) { socialLinks = []; } %>\n              <% if (!socialLinks.length) { %>\n                <a href=\"https://www.facebook.com/people/Aaryawart-Seva-Nyaas/61585981201970/\" class=\"text-white text-decoration-none\" aria-label=\"Facebook\"><i class=\"bi bi-facebook\"></i></a>\n                <a href=\"https://x.com/aaryawartastro\" class=\"text-white text-decoration-none\" aria-label=\"Twitter\"><i class=\"bi bi-twitter-x\"></i></a>\n                <a href=\"https://www.instagram.com/aaryawart_seva_nyaas/\" class=\"text-white text-decoration-none\" aria-label=\"Instagram\"><i class=\"bi bi-instagram\"></i></a>\n                <a href=\"https://www.youtube.com/@aaryawartastroworld\" class=\"text-white text-decoration-none\" aria-label=\"YouTube\"><i class=\"bi bi-youtube\"></i></a>\n                <a href=\"https://linkedin.com\" class=\"text-white text-decoration-none\" aria-label=\"LinkedIn\"><i class=\"bi bi-linkedin\"></i></a>\n              <% } else { %>\n                <% socialLinks.forEach(function(link) { %>\n                  <a href=\"<%= link.url %>\" class=\"text-white text-decoration-none\" aria-label=\"<%= link.id %>\"><i class=\"bi <%= link.icon %>\"></i></a>\n                <% }); %>\n              <% } %>\n            </div>\n          </div>\n        </div>\n      </nav>\n      <div class=\"news-ticker bg-warning text-dark\">\n        <div class=\"container\">\n          <span class=\"fw-bold me-2\">Latest:</span>\n          <marquee behavior=\"scroll\" direction=\"left\">\n            <%= (settings && settings.news_ticker_text) || 'Upcoming health camp in rural districts \u2022 National youth leadership workshop \u2022 Flood relief volunteer deployment \u2022 New education centers inaugurated' %>\n          </marquee>\n        </div>\n      </div>\n    </header>\n\n    <main>\n\n<section class=\"py-5\">\n    <div class=\"container\">\n      <h1 class=\"mb-4\">About Us</h1>\n      <div class=\"row\">\n        <div class=\"col-md-8\">\n          <h3>Our History</h3>\n          <p>\n            Founded by dedicated social workers and cultural leaders, our organization has grown from a small circle\n            of volunteers into a nationwide movement working in thousands of villages and towns.\n          </p>\n          <ul class=\"timeline\">\n            <li>\n              <div class=\"timeline-year\">1980s</div>\n              <div class=\"timeline-content\">Grassroots seva activities begin in select districts.</div>\n            </li>\n            <li>\n              <div class=\"timeline-year\">1990s</div>\n              <div class=\"timeline-content\">Expansion into education, health, and rural development programs.</div>\n            </li>\n            <li>\n              <div class=\"timeline-year\">2000s</div>\n              <div class=\"timeline-content\">Nationwide volunteer network; large-scale disaster relief operations.</div>\n            </li>\n            <li>\n              <div class=\"timeline-year\">2010s</div>\n              <div class=\"timeline-content\">Women empowerment, youth leadership, and environmental initiatives amplified.</div>\n            </li>\n            <li>\n              <div class=\"timeline-year\">2020s</div>\n              <div class=\"timeline-content\">Digital outreach, e-learning, telemedicine, and global partnerships.</div>\n            </li>\n          </ul>\n        </div>\n        <div class=\"col-md-4\">\n          <h3>Core Values</h3>\n          <ul class=\"list-group mb-3\">\n            <li class=\"list-group-item\">Selfless Service (Seva)</li>\n            <li class=\"list-group-item\">National Integration</li>\n            <li class=\"list-group-item\">Cultural Heritage</li>\n            <li class=\"list-group-item\">Social Harmony</li>\n            <li class=\"list-group-item\">Empowerment of the Marginalized</li>\n          </ul>\n          <h3>Leadership</h3>\n          <p class=\"small\">\n            The organization is guided by an all-India governing body, state-level committees, and local coordinators,\n            supported by thematic panels for education, health, women, youth, and environment.\n          </p>\n        </div>\n      </div>\n\n      <hr class=\"my-5\" />\n\n      <h2 class=\"mb-3\">Leadership & Team</h2>\n      <div class=\"row row-cols-1 row-cols-md-3 g-3\">\n        <div class=\"col\">\n          <div class=\"card h-100 text-center\">\n            <img src=\"/static/images/leader1.jpg\" class=\"card-img-top\" alt=\"Leader 1\" />\n            <div class=\"card-body\">\n              <h5 class=\"card-title\">Shri A. Sharma</h5>\n              <p class=\"card-text small\">National President</p>\n            </div>\n          </div>\n        </div>\n        <div class=\"col\">\n          <div class=\"card h-100 text-center\">\n            <img src=\"/static/images/leader2.jpg\" class=\"card-img-top\" alt=\"Leader 2\" />\n            <div class=\"card-body\">\n              <h5 class=\"card-title\">Dr. B. Iyer</h5>\n              <p class=\"card-text small\">General Secretary</p>\n            </div>\n          </div>\n        </div>\n        <div class=\"col\">\n          <div class=\"card h-100 text-center\">\n            <img src=\"/static/images/leader3.jpg\" class=\"card-img-top\" alt=\"Leader 3\" />\n            <div class=\"card-body\">\n              <h5 class=\"card-title\">Smt. C. Devi</h5>\n              <p class=\"card-text small\">Women & Family Affairs</p>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <hr class=\"my-5\" />\n\n      <h2 class=\"mb-3\">Organizational Structure</h2>\n      <div class=\"org-chart\">\n        <div class=\"org-level\">National Council</div>\n        <div class=\"org-connector\">\u2193</div>\n        <div class=\"org-level\">State Councils</div>\n        <div class=\"org-connector\">\u2193</div>\n        <div class=\"org-level\">District Committees</div>\n        <div class=\"org-connector\">\u2193</div>\n        <div class=\"org-level\">Taluka / Block Teams</div>\n        <div class=\"org-connector\">\u2193</div>\n        <div class=\"org-level\">Village / Ward Units</div>\n      </div>\n\n      <hr class=\"my-5\" />\n\n      <h2 class=\"mb-3\">Annual Reports & Partners</h2>\n      <p>Download recent annual reports (sample placeholders, replace with real PDFs):</p>\n      <ul>\n        <li><a href=\"/static/docs/annual-report-2023.pdf\" target=\"_blank\">Annual Report 2023</a></li>\n        <li><a href=\"/static/docs/annual-report-2022.pdf\" target=\"_blank\">Annual Report 2022</a></li>\n      </ul>\n\n      <h3 class=\"mt-4\">Affiliates & Partners</h3>\n      <p class=\"small\">\n        The organization works closely with like-minded social service institutions, hospitals, educational trusts,\n        and corporate social responsibility (CSR) partners across India and abroad.\n      </p>\n    </div>\n  </section>\n\n    </main>\n\n    <footer class=\"bg-dark text-white mt-5 pt-4 pb-3\">\n      <div class=\"container\">\n        <div class=\"row\">\n          <div class=\"col-md-4 mb-3\">\n            <h5>About</h5>\n            <p class=\"small\">\n              <%= (settings && settings.footer_about) || 'A nationwide social and cultural organization dedicated to selfless service, character building, and national integration through thousands of volunteers and grassroots projects.' %>\n            </p>\n          </div>\n          <div class=\"col-md-4 mb-3\">\n            <h5>Quick Links</h5>\n            <ul class=\"list-unstyled small\">\n              <% let quickLinks = []; try { quickLinks = settings && settings.footer_quick_links_json ? JSON.parse(settings.footer_quick_links_json) : []; } catch (e) { quickLinks = []; } %>\n              <% if (!quickLinks.length) { %>\n                <li><a href=\"/about\" class=\"text-white text-decoration-none\">About Us</a></li>\n                <li><a href=\"/activities\" class=\"text-white text-decoration-none\">Activities</a></li>\n                <li><a href=\"/media\" class=\"text-white text-decoration-none\">Media</a></li>\n                <li><a href=\"/get-involved\" class=\"text-white text-decoration-none\">Volunteer / Donate</a></li>\n                <li><a href=\"/contact\" class=\"text-white text-decoration-none\">Contact</a></li>\n              <% } else { %>\n                <% quickLinks.forEach(function(link) { %>\n                  <li><a href=\"<%= link.url %>\" class=\"text-white text-decoration-none\"><%= link.label %></a></li>\n                <% }); %>\n              <% } %>\n            </ul>\n          </div>\n          <div class=\"col-md-4 mb-3\">\n            <h5>Contact</h5>\n            <% const footerContact = (settings && settings.footer_contact) || '113, Shivalik Nagar, BHEL, Haridwar, UK, India (249403)\\nEmail: aaryawartsevanyaas@gmail.com\\nPhone: +91-9253999082, 9253999083'; %>\n            <% footerContact.split(/\\r?\\n/).forEach(function(line) { %>\n              <p class=\"small mb-1\"><%= line %></p>\n            <% }); %>\n          </div>\n        </div>\n        <div class=\"text-center small mt-3\">\n          &copy; <%= new Date().getFullYear() %> <%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %>. All rights reserved.\n        </div>\n      </div>\n    </footer>\n\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js\"></script>\n    <script src=\"/static/js/main.js\"></script>\n  </body>\n</html>\n";
views["activities.ejs"] = "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <title><%= title %> - <%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %></title>\n    <meta name=\"description\" content=\"Official website of <%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %>, a social and charity organization focusing on education, healthcare, rural development, women empowerment, youth, culture, and environment.\" />\n    <link\n      href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\"\n      rel=\"stylesheet\"\n    />\n    <link\n      rel=\"stylesheet\"\n      href=\"https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.3/font/bootstrap-icons.css\"\n    />\n    <link rel=\"stylesheet\" href=\"/static/css/style.css\" />\n  </head>\n  <body>\n    <header class=\"border-bottom bg-light\">\n      <div class=\"container py-2 py-md-2 d-flex flex-wrap justify-content-between align-items-center gap-2\">\n        <div class=\"d-flex align-items-center gap-2 gap-md-3 flex-shrink-0 min-w-0\">\n          <img src=\"<%= (settings && settings.header_logo_url) || '/static/images/logo.png' %>\" alt=\"Logo\" class=\"logo-img flex-shrink-0\" />\n          <div class=\"min-w-0\">\n            <span class=\"fw-bold text-primary d-block text-truncate\" style=\"font-size: clamp(0.9rem, 3vw, 1rem);\"><%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %></span>\n            <small class=\"text-muted d-none d-sm-inline\"><%= (settings && settings.site_tagline) || 'Seva | Shiksha | Sahyog' %></small>\n          </div>\n        </div>\n        <div class=\"d-none d-md-flex gap-2 flex-shrink-0\">\n          <a href=\"/get-involved\" class=\"btn btn-outline-primary btn-sm\">Join Us</a>\n          <a href=\"/get-involved#donate\" class=\"btn btn-primary btn-sm\">Donate</a>\n        </div>\n      </div>\n      <div class=\"container d-md-none mt-2 pb-2\">\n        <div class=\"d-flex justify-content-center gap-2\">\n          <a href=\"/get-involved\" class=\"btn btn-outline-primary btn-sm flex-grow-1 flex-md-grow-0\" style=\"min-width: 0;\">Join</a>\n          <a href=\"/get-involved#donate\" class=\"btn btn-primary btn-sm flex-grow-1 flex-md-grow-0\" style=\"min-width: 0;\">Donate</a>\n        </div>\n      </div>\n      <nav class=\"navbar navbar-expand-lg navbar-dark bg-primary\">\n        <div class=\"container\">\n          <a class=\"navbar-brand\" href=\"/\">Home</a>\n          <button\n            class=\"navbar-toggler\"\n            type=\"button\"\n            data-bs-toggle=\"collapse\"\n            data-bs-target=\"#mainNav\"\n            aria-controls=\"mainNav\"\n            aria-expanded=\"false\"\n            aria-label=\"Toggle navigation\"\n          >\n            <span class=\"navbar-toggler-icon\"></span>\n          </button>\n          <div class=\"collapse navbar-collapse\" id=\"mainNav\">\n            <ul class=\"navbar-nav me-auto mb-2 mb-lg-0\">\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/about\">About Us</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/activities\">Activities &amp; Programs</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/media\">Media &amp; Publications</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/get-involved\">Get Involved</a></li>\n              <li class=\"nav-item\"><a class=\"nav-link\" href=\"/contact\">Contact</a></li>\n            </ul>\n            <div class=\"d-flex gap-3 py-2 py-lg-0 justify-content-center justify-content-lg-end flex-wrap\">\n              <% let socialLinks = []; try { socialLinks = settings && settings.social_links_json ? JSON.parse(settings.social_links_json) : []; } catch (e) { socialLinks = []; } %>\n              <% if (!socialLinks.length) { %>\n                <a href=\"https://www.facebook.com/people/Aaryawart-Seva-Nyaas/61585981201970/\" class=\"text-white text-decoration-none\" aria-label=\"Facebook\"><i class=\"bi bi-facebook\"></i></a>\n                <a href=\"https://x.com/aaryawartastro\" class=\"text-white text-decoration-none\" aria-label=\"Twitter\"><i class=\"bi bi-twitter-x\"></i></a>\n                <a href=\"https://www.instagram.com/aaryawart_seva_nyaas/\" class=\"text-white text-decoration-none\" aria-label=\"Instagram\"><i class=\"bi bi-instagram\"></i></a>\n                <a href=\"https://www.youtube.com/@aaryawartastroworld\" class=\"text-white text-decoration-none\" aria-label=\"YouTube\"><i class=\"bi bi-youtube\"></i></a>\n                <a href=\"https://linkedin.com\" class=\"text-white text-decoration-none\" aria-label=\"LinkedIn\"><i class=\"bi bi-linkedin\"></i></a>\n              <% } else { %>\n                <% socialLinks.forEach(function(link) { %>\n                  <a href=\"<%= link.url %>\" class=\"text-white text-decoration-none\" aria-label=\"<%= link.id %>\"><i class=\"bi <%= link.icon %>\"></i></a>\n                <% }); %>\n              <% } %>\n            </div>\n          </div>\n        </div>\n      </nav>\n      <div class=\"news-ticker bg-warning text-dark\">\n        <div class=\"container\">\n          <span class=\"fw-bold me-2\">Latest:</span>\n          <marquee behavior=\"scroll\" direction=\"left\">\n            <%= (settings && settings.news_ticker_text) || 'Upcoming health camp in rural districts \u2022 National youth leadership workshop \u2022 Flood relief volunteer deployment \u2022 New education centers inaugurated' %>\n          </marquee>\n        </div>\n      </div>\n    </header>\n\n    <main>\n\n<section class=\"py-5\">\n    <div class=\"container\">\n      <h1 class=\"mb-4\">Activities & Programs</h1>\n      <div class=\"row row-cols-1 row-cols-md-2 g-4\">\n        <div class=\"col\">\n          <div class=\"card h-100\">\n            <div class=\"card-body\">\n              <h3 class=\"card-title\">Education Initiatives</h3>\n              <p class=\"card-text\">\n                Evening tuition centers, competitive exam coaching, hostels for rural students,\n                and value-based education workshops in schools and colleges.\n              </p>\n            </div>\n          </div>\n        </div>\n        <div class=\"col\">\n          <div class=\"card h-100\">\n            <div class=\"card-body\">\n              <h3 class=\"card-title\">Healthcare Services</h3>\n              <p class=\"card-text\">\n                Free medical camps, telemedicine, blood donation drives, eye check-up camps,\n                nutrition support for children, and elderly care services.\n              </p>\n            </div>\n          </div>\n        </div>\n        <div class=\"col\">\n          <div class=\"card h-100\">\n            <div class=\"card-body\">\n              <h3 class=\"card-title\">Rural Development</h3>\n              <p class=\"card-text\">\n                Village adoption, watershed management, organic farming promotion,\n                self-help groups, and livelihood training for farmers and artisans.\n              </p>\n            </div>\n          </div>\n        </div>\n        <div class=\"col\">\n          <div class=\"card h-100\">\n            <div class=\"card-body\">\n              <h3 class=\"card-title\">Women Empowerment</h3>\n              <p class=\"card-text\">\n                Skill development, self-defense training, health awareness, leadership workshops,\n                and support networks for women entrepreneurs.\n              </p>\n            </div>\n          </div>\n        </div>\n        <div class=\"col\">\n          <div class=\"card h-100\">\n            <div class=\"card-body\">\n              <h3 class=\"card-title\">Disaster Relief</h3>\n              <p class=\"card-text\">\n                Swift response teams for floods, earthquakes, and pandemics;\n                distribution of relief materials, rehabilitation, and psychological support.\n              </p>\n            </div>\n          </div>\n        </div>\n        <div class=\"col\">\n          <div class=\"card h-100\">\n            <div class=\"card-body\">\n              <h3 class=\"card-title\">Cultural Preservation</h3>\n              <p class=\"card-text\">\n                Festivals, traditional arts, Sanskrit promotion, heritage walks, and\n                inter-cultural dialogue in the spirit of harmony.\n              </p>\n            </div>\n          </div>\n        </div>\n        <div class=\"col\">\n          <div class=\"card h-100\">\n            <div class=\"card-body\">\n              <h3 class=\"card-title\">Youth Programs</h3>\n              <p class=\"card-text\">\n                Leadership camps, personality development, sports, adventure treks,\n                and nation-building projects led by students and young professionals.\n              </p>\n            </div>\n          </div>\n        </div>\n        <div class=\"col\">\n          <div class=\"card h-100\">\n            <div class=\"card-body\">\n              <h3 class=\"card-title\">Environmental Projects</h3>\n              <p class=\"card-text\">\n                Tree plantation drives, cleanliness campaigns, plastic-free initiatives,\n                river and lake rejuvenation, and environmental education.\n              </p>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </section>\n\n    </main>\n\n    <footer class=\"bg-dark text-white mt-5 pt-4 pb-3\">\n      <div class=\"container\">\n        <div class=\"row\">\n          <div class=\"col-md-4 mb-3\">\n            <h5>About</h5>\n            <p class=\"small\">\n              <%= (settings && settings.footer_about) || 'A nationwide social and cultural organization dedicated to selfless service, character building, and national integration through thousands of volunteers and grassroots projects.' %>\n            </p>\n          </div>\n          <div class=\"col-md-4 mb-3\">\n            <h5>Quick Links</h5>\n            <ul class=\"list-unstyled small\">\n              <% let quickLinks = []; try { quickLinks = settings && settings.footer_quick_links_json ? JSON.parse(settings.footer_quick_links_json) : []; } catch (e) { quickLinks = []; } %>\n              <% if (!quickLinks.length) { %>\n                <li><a href=\"/about\" class=\"text-white text-decoration-none\">About Us</a></li>\n                <li><a href=\"/activities\" class=\"text-white text-decoration-none\">Activities</a></li>\n                <li><a href=\"/media\" class=\"text-white text-decoration-none\">Media</a></li>\n                <li><a href=\"/get-involved\" class=\"text-white text-decoration-none\">Volunteer / Donate</a></li>\n                <li><a href=\"/contact\" class=\"text-white text-decoration-none\">Contact</a></li>\n              <% } else { %>\n                <% quickLinks.forEach(function(link) { %>\n                  <li><a href=\"<%= link.url %>\" class=\"text-white text-decoration-none\"><%= link.label %></a></li>\n                <% }); %>\n              <% } %>\n            </ul>\n          </div>\n          <div class=\"col-md-4 mb-3\">\n            <h5>Contact</h5>\n            <% const footerContact = (settings && settings.footer_contact) || '113, Shivalik Nagar, BHEL, Haridwar, UK, India (249403)\\nEmail: aaryawartsevanyaas@gmail.com\\nPhone: +91-9253999082, 9253999083'; %>\n            <% footerContact.split(/\\r?\\n/).forEach(function(line) { %>\n              <p class=\"small mb-1\"><%= line %></p>\n            <% }); %>\n          </div>\n        </div>\n        <div class=\"text-center small mt-3\">\n          &copy; <%= new Date().getFullYear() %> <%= (settings && settings.site_name) || 'Aaryawart Seva Nyaas' %>. All rights reserved.\n        </div>\n      </div>\n    </footer>\n\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js\"></script>\n    <script src=\"/static/js/main.js\"></script>\n  </body>\n</html>\n";
